import{_ as a,o,c as i,a0 as t}from"./chunks/framework.BjpW4enL.js";const p=JSON.parse('{"title":"ADR-0023: Pipeline Evolution — AST-Aware Chunking & Context GC (Observabilidade)","description":"","frontmatter":{},"headers":[],"relativePath":"20_Arquitetura/adr/0023-pipeline-evolution-context-gc.md","filePath":"20_Arquitetura/adr/0023-pipeline-evolution-context-gc.md","lastUpdated":1782592277000}'),r={name:"20_Arquitetura/adr/0023-pipeline-evolution-context-gc.md"};function s(n,e,d,l,c,u){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="adr-0023-pipeline-evolution-—-ast-aware-chunking-context-gc-observabilidade" tabindex="-1">ADR-0023: Pipeline Evolution — AST-Aware Chunking &amp; Context GC (Observabilidade) <a class="header-anchor" href="#adr-0023-pipeline-evolution-—-ast-aware-chunking-context-gc-observabilidade" aria-label="Permalink to &quot;ADR-0023: Pipeline Evolution — AST-Aware Chunking &amp; Context GC (Observabilidade)&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Accepted (Proposed by Sisyphus, Accepted by User)</p><h2 id="contexto" tabindex="-1">Contexto <a class="header-anchor" href="#contexto" aria-label="Permalink to &quot;Contexto&quot;">​</a></h2><p>O pipeline atual do NEXUS (ingest/enrichment) enfrenta problemas operacionais de vazão e qualidade de contexto:</p><ol><li><strong>Chunking ingênuo (<code>chunk_text</code>)</strong>: Divide arquivos por linhas em branco com um limite de 2500 caracteres, quebrando funções e estruturas de código no meio.</li><li><strong>Incompatibilidade com AST (L1)</strong>: Como os chunks possuem sintaxe quebrada, o <code>ast-grep</code> precisa re-ler os arquivos cheios para extrair constructos, gerando retrabalho.</li><li><strong>Gargalo de vazão (Lock do Ollama)</strong>: O lock global <code>ollama_model_lock()</code> impede paralelismo real entre geração semântica (L2) e embeddings.</li><li><strong>Acúmulo de contexto (Ghost vectors)</strong>: Qdrant acumula vetores órfãos de versões antigas sem expiração ou limpeza.</li></ol><p>Diante disso, cogitou-se adicionar Redis (filas/streams), aumentar o tamanho do chunk arbitrariamente ou realizar um rebuild completo. Porém, em uma máquina com recursos limitados (8GB RAM, Fedora Silverblue), adicionar infraestrutura sem sanar as causas raiz de qualidade de contexto apenas &quot;aceleraria o processamento de lixo&quot;.</p><h2 id="decisao" tabindex="-1">Decisão <a class="header-anchor" href="#decisao" aria-label="Permalink to &quot;Decisão&quot;">​</a></h2><p>Adotamos a estratégia de <strong>refatoração incremental focada em qualidade e descarte</strong>, dividida em duas frentes imediatas:</p><ol><li><strong>AST-Aware Chunking (Dry-Run)</strong>: Substituir o split textual por divisão baseada nas fronteiras naturais do código (AST do <code>ast-grep</code>). Faremos um dry-run comparativo antes de alterar o pipeline de gravação.</li><li><strong>Context GC &amp; Métrica <code>tokens·hora</code> (Observabilidade)</strong>: Em vez de focar apenas em compressão de contexto, criaremos mecanismos para mensurar o &quot;custo cognitivo&quot; e identificar subcontextos e memórias descartáveis que não geraram decisões ou conexões úteis no grafo.</li></ol><p>Rejeitamos para o momento inicial:</p><ul><li><strong>Redis/Workers</strong>: Adiciona complexidade de rede e sincronização desnecessária para uso local-first de 8GB RAM antes de otimizar o tamanho do lote.</li><li><strong>Rebuild completo</strong>: O coordenador em Rust possui excelente modularização; os problemas são de sequenciamento de loops e sintaxe de chunking, facilmente tratáveis com refatorações pontuais.</li></ul><hr><h2 id="alternativas-consideradas" tabindex="-1">Alternativas Consideradas <a class="header-anchor" href="#alternativas-consideradas" aria-label="Permalink to &quot;Alternativas Consideradas&quot;">​</a></h2><h3 id="opcao-a-apenas-aumentar-chunk-size" tabindex="-1">Opção A: Apenas aumentar CHUNK_SIZE <a class="header-anchor" href="#opcao-a-apenas-aumentar-chunk-size" aria-label="Permalink to &quot;Opção A: Apenas aumentar CHUNK_SIZE&quot;">​</a></h3><ul><li><strong>Pros</strong>: Zero alteração de código complexa.</li><li><strong>Cons</strong>: Não resolve o split por linha em branco (blank-line). Chunks continuam quebrando no meio de funções.</li></ul><h3 id="opcao-b-adicionar-redis-streams-imediatamente" tabindex="-1">Opção B: Adicionar Redis Streams imediatamente <a class="header-anchor" href="#opcao-b-adicionar-redis-streams-imediatamente" aria-label="Permalink to &quot;Opção B: Adicionar Redis Streams imediatamente&quot;">​</a></h3><ul><li><strong>Pros</strong>: Permite múltiplos workers escalarem horizontalmente.</li><li><strong>Cons</strong>: Consome RAM preciosa (limite de 8GB), adiciona latência de serialização, e apenas mascara a ineficiência do chunking ingênuo.</li></ul><h3 id="opcao-c-rebuild-completo-do-coordenador" tabindex="-1">Opção C: Rebuild completo do Coordenador <a class="header-anchor" href="#opcao-c-rebuild-completo-do-coordenador" aria-label="Permalink to &quot;Opção C: Rebuild completo do Coordenador&quot;">​</a></h3><ul><li><strong>Pros</strong>: Permite desenhar o pipeline do zero.</li><li><strong>Cons</strong>: Alto custo de tempo, descarte de features complexas já maduras (hallucination, PPR walk, decay estigmérgico).</li></ul><hr><h2 id="consequencias" tabindex="-1">Consequências <a class="header-anchor" href="#consequencias" aria-label="Permalink to &quot;Consequências&quot;">​</a></h2><h3 id="positivas" tabindex="-1">Positivas <a class="header-anchor" href="#positivas" aria-label="Permalink to &quot;Positivas&quot;">​</a></h3><ul><li><strong>Redução drástica no número de chunks</strong>: Agrupar estruturas de código íntegras reduzirá as chamadas de LLM (L2) e Qdrant em até 10x para arquivos estruturados.</li><li><strong>Observabilidade real de custo</strong>: A métrica <code>tokens·hora</code> permitirá sabermos quais partes da memória do agente estão gerando valor (decisões) ou apenas consumindo RAM de contexto.</li><li><strong>Fidelidade semântica</strong>: O LLM analisará funções inteiras, não pedaços cortados.</li></ul><h3 id="negativas" tabindex="-1">Negativas <a class="header-anchor" href="#negativas" aria-label="Permalink to &quot;Negativas&quot;">​</a></h3><ul><li>Adiciona processamento inicial de AST (via ast-grep) no passo de ingest.</li><li>Exige modelagem de logs de eventos para rastrear a utilidade das decisões.</li></ul><hr><h2 id="plano-de-implementacao-imediato-galhos-de-possibilidade" tabindex="-1">Plano de Implementação Imediato (Galhos de Possibilidade) <a class="header-anchor" href="#plano-de-implementacao-imediato-galhos-de-possibilidade" aria-label="Permalink to &quot;Plano de Implementação Imediato (Galhos de Possibilidade)&quot;">​</a></h2><h3 id="fase-1-dry-run-do-ast-chunking-sem-alteracao-de-db" tabindex="-1">Fase 1: Dry-Run do AST Chunking (Sem alteração de DB) <a class="header-anchor" href="#fase-1-dry-run-do-ast-chunking-sem-alteracao-de-db" aria-label="Permalink to &quot;Fase 1: Dry-Run do AST Chunking (Sem alteração de DB)&quot;">​</a></h3><ul><li>Criar ferramenta utilitária no engine ou script que simula o <code>chunk_by_ast()</code> comparado com <code>chunk_text()</code>.</li><li>Gerar estatísticas de volumetria, tamanho médio de chunks e cobertura de constructos por chunk.</li></ul><h3 id="fase-2-instrumentacao-de-context-gc-tokens·hora" tabindex="-1">Fase 2: Instrumentação de Context GC / <code>tokens·hora</code> <a class="header-anchor" href="#fase-2-instrumentacao-de-context-gc-tokens·hora" aria-label="Permalink to &quot;Fase 2: Instrumentação de Context GC / `tokens·hora`&quot;">​</a></h3><ul><li>Implementar log passivo de eventos cognitivos (quantos tokens entraram/saíram das chamadas Ollama, tempo de vida na sessão, e se gerou algum link no grafo).</li><li>Identificar candidatos a descarte (contextos órfãos com alto <code>tokens·hora</code>).</li></ul><h3 id="fase-3-decoupling-l1-l2-lock-tuning" tabindex="-1">Fase 3: Decoupling L1/L2 &amp; Lock Tuning <a class="header-anchor" href="#fase-3-decoupling-l1-l2-lock-tuning" aria-label="Permalink to &quot;Fase 3: Decoupling L1/L2 &amp; Lock Tuning&quot;">​</a></h3><ul><li>Separar o loop de extração AST do loop de LLM em threads/loops independentes.</li><li>Substituir o lock do Ollama por semáforos específicos por modelo.</li></ul>',34)])])}const h=a(r,[["render",s]]);export{p as __pageData,h as default};
